      font-size: 0.8rem; font-weight: 600;
      letter-spacing: 0.05em; margin-bottom: 1.5rem;
      opacity: 0;
    }
    .hero h1 {
      font-size: clamp(3rem, 8vw, 7rem);
      font-weight: 900; line-height: 1.0;
      letter-spacing: -2px;
      max-width: 900px;
