    }
    .btn-primary:hover { transform: translateY(-2px); opacity: 0.9; }
    .btn-ghost {
      border: 1px solid rgba(255,255,255,0.2); color: var(--text);
      padding: 0.85rem 2rem; border-radius: 100px;
      font-weight: 600; font-size: 0.95rem;
      text-decoration: none; transition: border-color 0.2s;
    }
    .btn-ghost:hover { border-color: var(--accent); color: var(--accent); }
    .hero-glow {
      position: absolute; width: 600px; height: 600px;
      background: radial-gradient(circle, rgba(200,246,93,0.08) 0%, transparent 70%);
      top: 10%; right: -10%; pointer-events: none;
    }
    .hero-glow2 {
      position: absolute; width: 400px; height: 400px;
      background: radial-gradient(circle, rgba(123,92,246,0.1) 0%, transparent 70%);
      bottom: 10%; left: -5%; pointer-events: none;
    }

